// إنشاء Vertex Buffer
VkDeviceSize bufferSize = sizeof(vertices[0]) * vertices.size();

VkBufferCreateInfo bufferInfo = {};
bufferInfo.sType = VK_STRUCTURE_TYPE_BUFFER_CREATE_INFO;
bufferInfo.size = bufferSize; // حجم المخزن بالبايت
bufferInfo.usage = VK_BUFFER_USAGE_VERTEX_BUFFER_BIT; // استخدام Vertex
bufferInfo.sharingMode = VK_SHARING_MODE_EXCLUSIVE; // طابور واحد

VkBuffer vertexBuffer;
VkResult result = vkCreateBuffer(
 device, &bufferInfo, nullptr, &vertexBuffer
);

if (result != VK_SUCCESS) {
 throw std::runtime_error("فشل إنشاء Vertex Buffer!");
}

